const body = $input.item.json.body;

if (!body.account_id || !body.company) {
  return [{ json: { ok: false, error: 'account_id and company are required' } }];
}

const inputPath = body.transcript_path || (body.company + '/transcripts/demo/transcript.txt');
const ext = inputPath.split('.').pop().toLowerCase();

const audioExts = ['mp3','wav','m4a','ogg','flac','webm','aac','wma','mp4','mpeg','mpga'];
const validExts = ['txt', ...audioExts];

if (!validExts.includes(ext)) {
  return [{ json: {
    ok: false,
    error: 'Unsupported file format: .' + ext + '. Supported: .txt, .' + audioExts.join(', .'),
    hint: 'Provide a .txt transcript or a Whisper-compatible audio file'
  }}];
}

return [{ json: {
  valid: true,
  account_id: body.account_id,
  company: body.company,
  transcript_path: body.transcript_path || null,
  input_type: ext === 'txt' ? 'transcript' : 'audio',
  ext: ext
}}];

const result = $input.item.json;
const ctx = $('Validate v1 Input').item.json;

if (!result.ok) {
  return [{ json: {
    ok: false,
    error: 'Pipeline A failed',
    account_id: ctx.account_id,
    company: ctx.company,
    details: result.error || result
  }}];
}

const memo = result.files?.memo || {};
const spec = result.files?.agentDraftSpec || {};

return [{ json: {
  ok: true,
  pipeline: 'A (demo -> v1)',
  account_id: ctx.account_id,
  company: ctx.company,
  version: result.version || 'v1',
  summary: {
    company_name: memo.company_name || ctx.company,
    industry: memo.industry_type || 'unknown',
    services_count: (memo.services_supported || []).length,
    business_hours: memo.business_hours || {},
    office_address: memo.office_address || null,
    emergency_contacts: (memo.emergency_routing_rules?.contacts || []).length,
    agent_name: spec.agent_name || 'unnamed',
    agent_id: spec.agent_id || null,
    llm_id: spec.llm_id || null,
    unknowns: memo.questions_or_unknowns || []
  }
}}];

const body = $input.item.json.body;

if (!body.account_id || !body.company) {
  return [{ json: { ok: false, error: 'account_id and company are required' } }];
}

const audioExts = ['mp3','wav','m4a','ogg','flac','webm','aac','wma','mp4','mpeg','mpga'];
const validExts = ['txt', ...audioExts];

const hasPath = !!body.onboarding_path;
const hasTranscript = !!body.transcript;
const hasForm = !!(body.form_data && typeof body.form_data === 'object' && Object.keys(body.form_data).length > 0);
const hasAny = hasPath || hasTranscript || hasForm;

if (!hasAny) {
  return [{ json: {
    ok: false,
    error: 'No input provided. Send at least one of: onboarding_path, transcript, or form_data'
  }}];
}

if (hasPath) {
  const ext = body.onboarding_path.split('.').pop().toLowerCase();
  if (!validExts.includes(ext)) {
    return [{ json: {
      ok: false,
      error: 'Unsupported file format: .' + ext + '. Supported: .txt, .' + audioExts.join(', .'),
      hint: 'Provide a .txt transcript or a Whisper-compatible audio file'
    }}];
  }
}

return [{ json: {
  valid: true,
  account_id: body.account_id,
  company: body.company,
  onboarding_path: body.onboarding_path || null,
  transcript: body.transcript || null,
  form_data: body.form_data || null,
  has_transcript_input: hasPath || hasTranscript,
  has_form: hasForm,
  input_summary: [
    hasPath ? ('path: ' + body.onboarding_path) : null,
    hasTranscript ? 'inline transcript' : null,
    hasForm ? ('form (' + Object.keys(body.form_data).length + ' fields)') : null
  ].filter(Boolean).join(' + ')
}}];

const result = $input.item.json;
const ctx = $('Validate v2 Input').item.json;

if (!result.ok) {
  return [{ json: {
    ok: false,
    error: 'Pipeline B failed',
    account_id: ctx.account_id,
    company: ctx.company,
    input_summary: ctx.input_summary,
    details: result.error || result
  }}];
}

const memo = result.files?.memo || {};
const spec = result.files?.agentDraftSpec || {};
const changes = result.files?.changes || {};

return [{ json: {
  ok: true,
  pipeline: 'B (onboarding -> v2)',
  account_id: ctx.account_id,
  company: ctx.company,
  version: result.version || 'v2',
  input_summary: ctx.input_summary,
  form_applied: result.form_applied || false,
  summary: {
    company_name: memo.company_name || ctx.company,
    total_changes: changes.total_changes || (changes.changes || []).length,
    source: changes.source || 'unknown',
    agent_name: spec.agent_name || 'unnamed',
    agent_id: spec.agent_id || null,
    llm_id: spec.llm_id || null,
    unknowns_remaining: memo.questions_or_unknowns || []
  }
}}];
